    with open(os.path.join(envoy_dir, "external_auth.proto"), "w") as f:
        f.write(EXTERNAL_AUTH_PROTO)
    
    # Create __init__.py files
    for dirpath, dirnames, filenames in os.walk(proto_dir):
        init_file = os.path.join(dirpath, "__init__.py")
        if not os.path.exists(init_file):
            open(init_file, "w").close()
    
    # Compile google.rpc.status first
    protoc.main([
        'grpc_tools.protoc',
        f'--proto_path={proto_dir}',
        f'--python_out={proto_dir}',
        f'--grpc_python_out={proto_dir}',
        os.path.join(google_rpc_dir, "status.proto"),
    ])
    
