def serve(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = 10,
    enable_reflection: bool = True,
):
    """
    Start the gRPC authorization server.
    
    Args:
        host: Host to bind to
        port: Port to listen on
        max_workers: Maximum number of worker threads
        enable_reflection: Enable gRPC server reflection
    """
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ("grpc.max_send_message_length", 10 * 1024 * 1024),  # 10MB
            ("grpc.max_receive_message_length", 10 * 1024 * 1024),  # 10MB
            ("grpc.keepalive_time_ms", 30000),  # 30 seconds
            ("grpc.keepalive_timeout_ms", 5000),  # 5 seconds
            ("grpc.keepalive_permit_without_calls", True),
            ("grpc.http2.max_pings_without_data", 0),
            ("grpc.http2.min_time_between_pings_ms", 10000),
        ],
    )
    
    # Create and register the authorization servicer
    auth_servicer = AuthorizationServicer()
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_servicer, server)
    
    # Enable server reflection for debugging with grpcurl
    if enable_reflection:
        SERVICE_NAMES = (
            external_auth_pb2.DESCRIPTOR.services_by_name['Authorization'].full_name,
            reflection.SERVICE_NAME,
        )
        reflection.enable_server_reflection(SERVICE_NAMES, server)
        logger.info("gRPC server reflection enabled")
    
    # Bind to address
    listen_addr = f"{host}:{port}"
    server.add_insecure_port(listen_addr)
    
    logger.info(f"Starting Envoy External Authorization gRPC server on {listen_addr}")
    logger.info(f"Max workers: {max_workers}")
    logger.info("Authorization policies loaded:")
    logger.info(f"  - API keys configured: {len(AuthorizationPolicy.VALID_API_KEYS)}")
    logger.info(f"  - Bearer tokens configured: {len(AuthorizationPolicy.VALID_BEARER_TOKENS)}")
    logger.info(f"  - Path rules configured: {len(AuthorizationPolicy.PATH_RULES)}")
    logger.info(f"  - Denied path patterns: {len(AuthorizationPolicy.DENIED_PATHS)}")
    
    server.start()
    logger.info("Server started successfully. Waiting for requests...")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)
        logger.info("Server stopped.")


def create_test_client():
    """
    Create a test client to verify the service works.
    
    Usage:
        python -c "from envoy_ext_authz import create_test_client; create_test_client()"
    """
    channel = grpc.insecure_channel("localhost:50051")
    stub = external_auth_pb2_grpc.AuthorizationStub(channel)
    
    print("=" * 60)
    print("Testing Envoy External Authorization Service")
    print("=" * 60)
    
    test_cases = [
        {
            "name": "Public health check (should allow)",
            "method": "GET",
            "path": "/health",
            "headers": {},
        },
        {
            "name": "No credentials to /api/v1/users (should deny 401)",
            "method": "GET",
            "path": "/api/v1/users",
            "headers": {},
        },
        {
            "name": "Valid API key to /api/v1/users (should allow)",
            "method": "GET",
            "path": "/api/v1/users",
            "headers": {"x-api-key": "key-user-001"},
        },
        {
            "name": "Valid admin API key to /admin (should allow)",
            "method": "GET",
            "path": "/admin/dashboard",
            "headers": {"x-api-key": "key-admin-001"},
        },
        {
            "name": "User API key to /admin (should deny 403)",
            "method": "GET",
            "path": "/admin/dashboard",
            "headers": {"x-api-key": "key-user-001"},
        },
        {
            "name": "Invalid API key (should deny 401)",
            "method": "GET",
            "path": "/api/v1/users",
            "headers": {"x-api-key": "invalid-key"},
        },
        {
            "name": "Bearer token auth (should allow)",
            "method": "GET",
            "path": "/api/v1/users",
            "headers": {"authorization": "Bearer token-user-secret"},
        },
        {
            "name": "Denied path /internal (should deny 403)",
            "method": "GET",
            "path": "/internal/secrets",
            "headers": {"x-api-key": "key-admin-001"},
        },
        {
            "name": "Path traversal attempt (should deny 403)",
            "method": "GET",
            "path": "/api/../../../etc/passwd",
            "headers": {"x-api-key": "key-admin-001"},
        },
        {
            "name": "User POST to /api/v1/content (should deny 403 - needs editor)",
            "method": "POST",
            "path": "/api/v1/content/article",
            "headers": {"x-api-key": "key-user-001"},
        },
        {
            "name": "Editor POST to /api/v1/content (should allow)",
            "method": "POST",
            "path": "/api/v1/content/article",
            "headers": {"x-api-key": "key-user-002"},  # bob has editor role
        },
    ]
    
    for i, tc in enumerate(test_cases, 1):
        print(f"\nTest {i}: {tc['name']}")
        print(f"  Request: {tc['method']} {tc['path']}")
        print(f"  Headers: {tc['headers']}")
        
        # Build CheckRequest
        http_request = external_auth_pb2.AttributeContext.HttpRequest(
            method=tc["method"],
            path=tc["path"],
            host="localhost",
            headers=tc["headers"],
        )
        
        attributes = external_auth_pb2.AttributeContext(
            request=http_request,
            source=external_auth_pb2.AttributeContext.Peer(
                address="127.0.0.1",
                port=12345,
            ),
        )
        
        check_request = external_auth_pb2.CheckRequest(attributes=attributes)
        
        try:
            response = stub.Check(check_request)
            
            if response.status.code == 0:
                print(f"  Result: ✅ ALLOWED")
                if response.ok_response.headers:
                    for h in response.ok_response.headers:
                        print(f"    Header: {h.header.key}={h.header.value}")
            else:
                print(f"  Result: ❌ DENIED (gRPC code={response.status.code})")
                if response.denied_response.body:
                    body = json.loads(response.denied_response.body)
                    print(f"    Status: {response.denied_response.status.code}")
                    print(f"    Error: {body.get('error', 'unknown')}")
                    print(f"    Message: {body.get('message', '')}")
                
        except grpc.RpcError as e:
            print(f"  Result: ⚠️  RPC Error: {e.code()} - {e.details()}")
    
    print("\n" + "=" * 60)
    print("Test suite complete")
    print("=" * 60)
    
    channel.close()


